29	/// Generate a human-readable order number: LOC-YYYYMMDD-XXXX
30	fn generate_order_number(location: &str, conn: &mut PgConnection) -> Result<String, AppError> {
31	    let date = Utc::now().format("%Y%m%d");
32	    let prefix = format!(
33	        "{}-{}",
34	        &location[..std::cmp::min(location.len(), 3)].to_uppercase(),
35	        date
36	    );
37	
38	    // Count existing orders with same prefix today
39	    let count: i64 = orders::table
40	        .filter(orders::order_number.like(format!("{}%", prefix)))
41	        .count()
42	        .get_result(conn)?;
43	
44	    Ok(format!("{}-{:04}", prefix, count + 1))
45	}
