47	pub async fn create_order(
48	    pool: web::Data<DbPool>,
49	    auth: AuthenticatedUser,
50	    req: HttpRequest,
51	    body: web::Json<CreateOrderRequest>,
52	) -> Result<HttpResponse, AppError> {
53	    body.validate()
54	        .map_err(|e| AppError::Validation(e.to_string()))?;
55	
56	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
57	    let _ctx = check_perm_req(&auth.0, "order.create", &req, &mut conn)?;
58	
59	    // Compute totals from line items
60	    let mut subtotal: i64 = 0;
61	    let mut tax: i64 = 0;
62	    for li in &body.line_items {
63	        let line_total = li.unit_price_cents * li.quantity as i64;
64	        subtotal += line_total;
65	        tax += li.tax_cents * li.quantity as i64;
66	    }
67	    let total = subtotal + tax;
68	
69	    let order_number = generate_order_number(&body.location, &mut conn)?;
70	
71	    // Insert order + line items in a transaction
72	    let (order, items) = conn.transaction::<_, AppError, _>(|conn| {
73	        let new_order = NewOrder {
74	            order_number,
75	            status: OrderStatus::Draft,
76	            cashier_user_id: auth.0.sub,
77	            location: body.location.clone(),
78	            department: body.department.clone(),
79	            customer_reference: body.customer_reference.clone(),
80	            original_order_id: None,
81	            subtotal_cents: subtotal,
82	            tax_cents: tax,
83	            total_cents: total,
84	            notes: body.notes.clone(),
85	        };
86	
87	        let order: Order = diesel::insert_into(orders::table)
88	            .values(&new_order)
89	            .get_result(conn)?;
90	
91	        let mut items = Vec::new();
92	        for li in &body.line_items {
93	            let line_total = li.unit_price_cents * li.quantity as i64;
94	            let new_item = NewOrderLineItem {
95	                order_id: order.id,
96	                sku: li.sku.clone(),
97	                description: li.description.clone(),
98	                quantity: li.quantity,
99	                unit_price_cents: li.unit_price_cents,
100	                tax_cents: li.tax_cents,
101	                line_total_cents: line_total,
102	                original_line_item_id: None,
103	            };
104	            let item: OrderLineItem = diesel::insert_into(order_line_items::table)
105	                .values(&new_item)
106	                .get_result(conn)?;
107	            items.push(item);
108	        }
109	
110	        Ok((order, items))
111	    })?;
112	
113	    // Audit: create with after-state hash
114	    let after = serde_json::json!({"order_id": order.id, "order_number": &order.order_number, "total_cents": order.total_cents});
115	    let _ = crate::audit::service::audit_write(&mut conn, auth.0.sub, "create", "orders", Some(order.id), None, Some(&after));
116	
117	    let response = OrderDetailResponse {
118	        order: OrderResponse::from(order),
119	        line_items: items.into_iter().map(OrderLineItemResponse::from).collect(),
120	        ledger_entries: vec![],
121	    };
122	
123	    Ok(HttpResponse::Created().json(response))
124	}
