126	pub async fn list_orders(
127	    pool: web::Data<DbPool>,
128	    auth: AuthenticatedUser,
129	    req: HttpRequest,
130	    query: web::Query<OrderQueryParams>,
131	) -> Result<HttpResponse, AppError> {
132	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
133	    let ctx = check_perm_req(&auth.0, "order.read", &req, &mut conn)?;
134	
135	    let page = query.page.unwrap_or(1).max(1);
136	    let per_page = query.per_page.unwrap_or(50).min(200);
137	    let offset = (page - 1) * per_page;
138	
139	    let mut q = orders::table.into_boxed();
140	
141	    // Data-scope filtering
142	    match ctx.data_scope.as_str() {
143	        "individual" => {
144	            q = q.filter(orders::cashier_user_id.eq(ctx.user_id));
145	        }
146	        "location" => {
147	            if let Some(ref loc) = ctx.location {
148	                q = q.filter(orders::location.eq(loc));
149	            }
150	        }
151	        "department" => {
152	            if let Some(ref dept) = ctx.department {
153	                q = q.filter(orders::department.eq(dept));
154	            }
155	        }
156	        _ => {} // unrestricted
157	    }
158	
159	    // Query param filters
160	    if let Some(ref status) = query.status {
161	        q = q.filter(orders::status.eq(status_from_str(status)?));
162	    }
163	    if let Some(ref loc) = query.location {
164	        q = q.filter(orders::location.eq(loc));
165	    }
166	
167	    let results: Vec<Order> = q
168	        .order(orders::created_at.desc())
169	        .offset(offset)
170	        .limit(per_page)
171	        .select(Order::as_select())
172	        .load(&mut conn)?;
173	
174	    let responses: Vec<OrderResponse> = results.into_iter().map(OrderResponse::from).collect();
175	    Ok(HttpResponse::Ok().json(responses))
176	}
