220	pub async fn update_order(
221	    pool: web::Data<DbPool>,
222	    auth: AuthenticatedUser,
223	    req: HttpRequest,
224	    path: web::Path<Uuid>,
225	    body: web::Json<UpdateOrderRequest>,
226	) -> Result<HttpResponse, AppError> {
227	    let order_id = path.into_inner();
228	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
229	    let ctx = check_perm_req(&auth.0, "order.update", &req, &mut conn)?;
230	
231	    let order: Order = orders::table
232	        .find(order_id)
233	        .select(Order::as_select())
234	        .first(&mut conn)?;
235	
236	    ctx.enforce_scope(order.cashier_user_id, order.department.as_deref(), Some(&order.location))?;
237	
238	    // Only allow updates in Draft or Open status
239	    if order.status != OrderStatus::Draft && order.status != OrderStatus::Open {
240	        return Err(AppError::Validation(
241	            "Order can only be updated in Draft or Open status".into(),
242	        ));
243	    }
244	
245	    conn.transaction::<_, AppError, _>(|conn| {
246	        // If line items are provided, replace them
247	        if let Some(ref new_items) = body.line_items {
248	            diesel::delete(order_line_items::table.filter(order_line_items::order_id.eq(order_id)))
249	                .execute(conn)?;
250	
251	            let mut subtotal: i64 = 0;
252	            let mut tax: i64 = 0;
253	            for li in new_items {
254	                let line_total = li.unit_price_cents * li.quantity as i64;
255	                subtotal += line_total;
256	                tax += li.tax_cents * li.quantity as i64;
257	
258	                let new_item = NewOrderLineItem {
259	                    order_id,
260	                    sku: li.sku.clone(),
261	                    description: li.description.clone(),
262	                    quantity: li.quantity,
263	                    unit_price_cents: li.unit_price_cents,
264	                    tax_cents: li.tax_cents,
265	                    line_total_cents: line_total,
266	                    original_line_item_id: None,
267	                };
268	                diesel::insert_into(order_line_items::table)
269	                    .values(&new_item)
270	                    .execute(conn)?;
271	            }
272	
273	            let total = subtotal + tax;
274	            diesel::update(orders::table.find(order_id))
275	                .set((
276	                    orders::subtotal_cents.eq(subtotal),
277	                    orders::tax_cents.eq(tax),
278	                    orders::total_cents.eq(total),
279	                    orders::updated_at.eq(Utc::now()),
280	                ))
281	                .execute(conn)?;
282	        }
283	
284	        // Update other fields
285	        let changeset = UpdateOrder {
286	            status: None,
287	            customer_reference: body.customer_reference.clone(),
288	            subtotal_cents: None,
289	            tax_cents: None,
290	            total_cents: None,
291	            notes: body.notes.clone(),
292	            updated_at: Utc::now(),
293	        };
294	        diesel::update(orders::table.find(order_id))
295	            .set(&changeset)
296	            .execute(conn)?;
297	
298	        Ok(())
299	    })?;
300	
301	    // Re-fetch and return
302	    let updated: Order = orders::table
303	        .find(order_id)
304	        .select(Order::as_select())
305	        .first(&mut conn)?;
306	    let items: Vec<OrderLineItem> = order_line_items::table
307	        .filter(order_line_items::order_id.eq(order_id))
308	        .select(OrderLineItem::as_select())
309	        .load(&mut conn)?;
310	
311	    let response = OrderDetailResponse {
312	        order: OrderResponse::from(updated),
313	        line_items: items.into_iter().map(OrderLineItemResponse::from).collect(),
314	        ledger_entries: vec![],
315	    };
316	
317	    Ok(HttpResponse::Ok().json(response))
318	}
