320	pub async fn transition_order(
321	    pool: web::Data<DbPool>,
322	    auth: AuthenticatedUser,
323	    req: HttpRequest,
324	    path: web::Path<Uuid>,
325	    body: web::Json<TransitionOrderRequest>,
326	) -> Result<HttpResponse, AppError> {
327	    let order_id = path.into_inner();
328	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
329	
330	    let ctx = check_perm_req(&auth.0, "order.transition", &req, &mut conn)?;
331	
332	    let order: Order = orders::table
333	        .find(order_id)
334	        .select(Order::as_select())
335	        .first(&mut conn)?;
336	
337	    // Object-level scope enforcement on target order
338	    ctx.enforce_scope(order.cashier_user_id, order.department.as_deref(), Some(&order.location))?;
339	
340	    // Validate transition
341	    if !state_machine::valid_transition(&order.status, &body.target_status) {
342	        return Err(AppError::Validation(format!(
343	            "Invalid transition from {:?} to {:?}",
344	            order.status, body.target_status
345	        )));
346	    }
347	
348	    // Check extra permissions for specific transitions
349	    if let Some(extra_perm) = state_machine::extra_permission_for_transition(&body.target_status) {
350	        // For reversals on orders older than 24h, use the late-reversal permission
351	        if (body.target_status == OrderStatus::ReversalPending
352	            || body.target_status == OrderStatus::Reversed)
353	            && order.created_at < Utc::now() - Duration::hours(24)
354	        {
355	            check_permission_no_approval(&auth.0, "order.reverse_late", &mut conn)?;
356	        } else {
357	            check_permission_no_approval(&auth.0, extra_perm, &mut conn)?;
358	        }
359	    }
360	
361	    // For stock/accounting-impacting transitions, check idempotency
362	    let is_impacting = matches!(
363	        body.target_status,
364	        OrderStatus::Returned | OrderStatus::Reversed
365	    );
366	    if is_impacting {
367	        let idemp_key = body.idempotency_key.ok_or_else(|| {
368	            AppError::Validation("idempotency_key required for this transition".into())
369	        })?;
370	        if let Some(cached) = check_idempotency(idemp_key, &mut conn)? {
371	            return Ok(cached);
372	        }
373	    }
374	
375	    // Capture before-state for audit
376	    let before_state = serde_json::json!({"order_id": order_id, "status": format!("{:?}", order.status)});
377	
378	    // Perform the transition
379	    diesel::update(orders::table.find(order_id))
380	        .set((
381	            orders::status.eq(&body.target_status),
382	            orders::updated_at.eq(Utc::now()),
383	        ))
384	        .execute(&mut conn)?;
385	
386	    let updated: Order = orders::table
387	        .find(order_id)
388	        .select(Order::as_select())
389	        .first(&mut conn)?;
390	
391	    let after_state = serde_json::json!({"order_id": order_id, "status": format!("{:?}", body.target_status)});
392	    let _ = crate::audit::service::audit_write(&mut conn, auth.0.sub, "update", "orders", Some(order_id), Some(&before_state), Some(&after_state));
393	
394	    let response = OrderResponse::from(updated);
395	
396	    // Store idempotency for impacting transitions
397	    if is_impacting {
398	        if let Some(key) = body.idempotency_key {
399	            let json = serde_json::to_value(&response)
400	                .map_err(|e| AppError::Internal(e.to_string()))?;
401	            store_idempotency(key, "order_transition", order_id, 200, &json, &mut conn)?;
402	        }
403	    }
404	
405	    Ok(HttpResponse::Ok().json(response))
406	}
