408	pub async fn add_payment(
409	    pool: web::Data<DbPool>,
410	    auth: AuthenticatedUser,
411	    req: HttpRequest,
412	    path: web::Path<Uuid>,
413	    body: web::Json<AddPaymentRequest>,
414	) -> Result<HttpResponse, AppError> {
415	    let order_id = path.into_inner();
416	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
417	    let ctx = check_perm_req(&auth.0, "order.add_payment", &req, &mut conn)?;
418	
419	    // Atomic idempotency: reserve key before mutation, inside validation scope
420	    if let Some(cached) = check_idempotency(body.idempotency_key, &mut conn)? {
421	        return Ok(cached);
422	    }
423	
424	    let order: Order = orders::table
425	        .find(order_id)
426	        .select(Order::as_select())
427	        .first(&mut conn)?;
428	
429	    ctx.enforce_scope(order.cashier_user_id, order.department.as_deref(), Some(&order.location))?;
430	
431	    if order.status != OrderStatus::Tendering {
432	        return Err(AppError::Validation(
433	            "Payments can only be added when order is in Tendering status".into(),
434	        ));
435	    }
436	
437	    if body.amount_cents <= 0 {
438	        return Err(AppError::Validation("Payment amount must be positive".into()));
439	    }
440	
441	    let entry = conn.transaction::<_, AppError, _>(|conn| {
442	        // Reserve idempotency key atomically inside transaction
443	        if let Some(cached_in_tx) = reserve_idempotency_key(body.idempotency_key, "ledger_entry", conn)? {
444	            // Race: another tx completed first — this is unreachable after outer check,
445	            // but provides defense-in-depth.
446	            return Err(AppError::Internal("idempotency_race".into()));
447	        }
448	
449	        let new_entry = NewLedgerEntry {
450	            order_id,
451	            tender_type: body.tender_type.clone(),
452	            entry_kind: LedgerEntryKind::Payment,
453	            amount_cents: body.amount_cents,
454	            reference_code: body.reference_code.clone(),
455	            idempotency_key: body.idempotency_key,
456	            created_by: auth.0.sub,
457	        };
458	
459	        let entry: LedgerEntry = diesel::insert_into(ledger_entries::table)
460	            .values(&new_entry)
461	            .get_result(conn)?;
462	
463	        // Check if total payments meet or exceed order total
464	        let paid_amounts: Vec<i64> = ledger_entries::table
465	            .filter(ledger_entries::order_id.eq(order_id))
466	            .filter(ledger_entries::entry_kind.eq(LedgerEntryKind::Payment))
467	            .select(ledger_entries::amount_cents)
468	            .load(conn)?;
469	        let total_paid: i64 = paid_amounts.iter().sum();
470	
471	        if total_paid >= order.total_cents {
472	            diesel::update(orders::table.find(order_id))
473	                .set((
474	                    orders::status.eq(OrderStatus::Paid),
475	                    orders::updated_at.eq(Utc::now()),
476	                ))
477	                .execute(conn)?;
478	        }
479	
480	        Ok(entry)
481	    })?;
482	
483	    let response = LedgerEntryResponse::from(entry);
484	
485	    let after = serde_json::json!({"order_id": order_id, "entry_id": response.id, "amount_cents": response.amount_cents});
486	    let _ = crate::audit::service::audit_write(&mut conn, auth.0.sub, "create", "ledger_entries", Some(response.id), None, Some(&after));
487	
488	    let json =
489	        serde_json::to_value(&response).map_err(|e| AppError::Internal(e.to_string()))?;
490	    // Finalize the atomically reserved key with actual response
491	    finalize_idempotency(body.idempotency_key, response.id, 201, &json, &mut conn)?;
492	
493	    Ok(HttpResponse::Created().json(response))
494	}
