520	/// Attach a receipt to an order. Accepts multipart/form-data with a file upload.
521	/// The file is stored locally with SHA-256 fingerprint. Allowed types: PDF/JPG/PNG/CSV/XLSX.
522	/// Max 10 MB. Also accepts a JSON `receipt_data` field for structured metadata.
523	pub async fn attach_receipt(
524	    pool: web::Data<DbPool>,
525	    auth: AuthenticatedUser,
526	    req: HttpRequest,
527	    path: web::Path<Uuid>,
528	    mut payload: actix_multipart::Multipart,
529	) -> Result<HttpResponse, AppError> {
530	    use futures_util::StreamExt;
531	
532	    let order_id = path.into_inner();
533	    let mut conn = pool.get().map_err(crate::errors::pool_err)?;
534	    let ctx = check_perm_req(&auth.0, "order.attach_receipt", &req, &mut conn)?;
535	
536	    let order: Order = orders::table
537	        .find(order_id)
538	        .select(Order::as_select())
539	        .first(&mut conn)?;
540	
541	    ctx.enforce_scope(order.cashier_user_id, order.department.as_deref(), Some(&order.location))?;
542	
543	    let count: i64 = receipts::table
544	        .filter(receipts::order_id.eq(order_id))
545	        .count()
546	        .get_result(&mut conn)?;
547	    let receipt_number = format!("RCP-{}-{}", order_id.to_string()[..8].to_uppercase(), count + 1);
548	
549	    let mut file_path_stored: Option<String> = None;
550	    let mut content_type_stored: Option<String> = None;
551	    let mut file_size: Option<i64> = None;
552	    let mut sha256: Option<String> = None;
553	    let mut receipt_data = serde_json::json!({});
554	
555	    while let Some(item) = payload.next().await {
556	        let mut field = item.map_err(|e| AppError::Validation(format!("Multipart error: {}", e)))?;
557	        let disposition = field.content_disposition()
558	            .ok_or_else(|| AppError::Validation("Missing content disposition".into()))?
559	            .clone();
560	        let field_name = disposition.get_name().unwrap_or("").to_string();
561	
562	        if field_name == "receipt_data" {
563	            // JSON metadata field
564	            let mut json_bytes = Vec::new();
565	            while let Some(chunk) = field.next().await {
566	                let chunk = chunk.map_err(|e| AppError::Internal(e.to_string()))?;
567	                json_bytes.extend_from_slice(&chunk);
568	            }
569	            receipt_data = serde_json::from_slice(&json_bytes)
